with Ada.Text_IO;

procedure Ada_First_Crate is
begin
   Ada.Text_IO.Put_Line ("Ada mastery begins.");
end Ada_First_Crate;

with Ada.Text_IO;

procedure Range_Checked_Altitude is
   subtype Altitude_Feet is Integer range 0 .. 60_000;
   Current_Altitude : Altitude_Feet := 12_500;
begin
   Ada.Text_IO.Put_Line (Altitude_Feet'Image (Current_Altitude));
end Range_Checked_Altitude;

type Position is record
   X : Integer := 0;
   Y : Integer := 0;
end record;

procedure Move
  (Location : in out Position;
   Delta_X  : in Integer;
   Delta_Y  : in Integer) is
begin
   Location.X := Location.X + Delta_X;
   Location.Y := Location.Y + Delta_Y;
end Move;
